const caption = $json.caption_result || {};

function normalizeRepoPath(value) {
  if (!value) return null;
  return String(value).replace(/^\.\//, '').replace(/\\/g, '/');
}

function toContainerPath(value) {
  if (!value) return null;
  const normalized = normalizeRepoPath(value);
  if (normalized.startsWith('/files/')) return normalized;
  if (normalized.startsWith('shared/')) return '/files/' + normalized.slice('shared/'.length);
  if (normalized.startsWith('/')) return normalized;
  return '/files/' + normalized;
}

function deriveTitle(text, fallback) {
  const source = String(text || '').replace(/\s+/g, ' ').trim();
  if (!source) return fallback;
  const sentence = source.split(/[.!?\n]/).map((s) => s.trim()).filter(Boolean)[0] || source;
  return sentence.slice(0, 100).trim() || fallback;
}

const platformTargets = Array.isArray(caption.platform_targets) ? caption.platform_targets : [];
const captionPacks = Array.isArray(caption.caption_pack) ? caption.caption_pack : [];
const youtubePack = captionPacks.find((item) => item && item.platform === 'youtube_shorts') || captionPacks[0] || null;
const hashtags = Array.isArray(youtubePack?.hashtags) && youtubePack.hashtags.length > 0
  ? youtubePack.hashtags
  : (Array.isArray(caption.hashtags) ? caption.hashtags : []);
const normalizedHashtags = hashtags.map((item) => String(item || '').trim()).filter(Boolean);
const captionText = String(youtubePack?.caption || '').trim();
const descriptionParts = [captionText, normalizedHashtags.join(' ')].filter(Boolean);
const manifestPathAbs = toContainerPath(caption.manifest_path);
const captionResultPathAbs = toContainerPath(caption.caption_result_path);
const youtubePublishResultPathAbs = manifestPathAbs
  ? manifestPathAbs.replace(/manifest\.json$/, 'youtube_publish_result.json')
  : null;
const derivedTitle = deriveTitle(captionText, 'Shorts ' + String(caption.job_id || '').trim());

return {
  json: {
    job_id: caption.job_id || null,
    manifest_path: manifestPathAbs,
    caption_result_path: captionResultPathAbs,
    youtube_publish_result_path: youtubePublishResultPathAbs,
    source_video_url: caption.source_video_url || null,
    source_video_id: caption.source_video_id || null,
    platform_targets: platformTargets,
    approval_mode: caption.approval_mode || 'required',
    caption_status: caption.status || null,
    title: derivedTitle,
    description: descriptionParts.join('\n\n').trim(),
    hashtags: normalizedHashtags,
    youtube_caption_pack: youtubePack,
    eligible_for_youtube_publish: caption.status === 'CAPTION_GENERATED'
      && platformTargets.includes('youtube_shorts')
      && Boolean(manifestPathAbs)
      && Boolean(youtubePublishResultPathAbs),
    caption_result: caption,
  }
};

const manifest = $json.manifest || {};

function normalizeRepoPath(value) {
  if (!value) return null;
  return String(value).replace(/^\.\//, '').replace(/\\/g, '/');
}

function toContainerPath(value) {
  if (!value) return null;
  const normalized = normalizeRepoPath(value);
  if (normalized.startsWith('/files/')) return normalized;
  if (normalized.startsWith('shared/')) return '/files/' + normalized.slice('shared/'.length);
  if (normalized.startsWith('/')) return normalized;
  return '/files/' + normalized;
}

return {
  json: {
    ...$json,
    manifest,
    clip_path_abs: toContainerPath(manifest.clip_path),
    clip_path: normalizeRepoPath(manifest.clip_path),
    thumbnail_path_abs: toContainerPath(manifest.thumbnail_path),
  }
};

const defaults = {
  privacy_status: 'private',
  category_id: '22',
  notify_subscribers: false,
  self_declared_made_for_kids: false,
  allow_publish_without_approval: true,
  title_suffix: '',
  description_footer: '',
};

function toBoolean(value, fallback) {
  if (value === undefined || value === null || value === '') return fallback;
  if (typeof value === 'boolean') return value;
  return ['1', 'true', 'yes', 'y', 'on'].includes(String(value).trim().toLowerCase());
}

let config = {};
let configError = null;
const binaryFieldName = $binary ? Object.keys($binary)[0] : null;

if (binaryFieldName) {
  try {
    const rawBuffer = await this.helpers.getBinaryDataBuffer(0, binaryFieldName);
    const parsed = JSON.parse(rawBuffer.toString('utf8'));
    if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
      config = parsed;
    } else {
      configError = 'Isi /files/config/youtube_oauth.json harus berupa object JSON.';
    }
  } catch (error) {
    configError = 'Config YouTube lokal tidak valid: ' + (error.message || 'parse gagal');
  }
}

return {
  json: {
    ...$json,
    youtube_config_path: '/files/config/youtube_oauth.json',
    youtube_config_error: configError,
    youtube_client_id: String(config.client_id || '').trim(),
    youtube_client_secret: String(config.client_secret || '').trim(),
    youtube_refresh_token: String(config.refresh_token || '').trim(),
    youtube_privacy_status: String(config.privacy_status || defaults.privacy_status),
    youtube_category_id: String(config.category_id || defaults.category_id),
    youtube_notify_subscribers: toBoolean(config.notify_subscribers, defaults.notify_subscribers),
    youtube_self_declared_made_for_kids: toBoolean(config.self_declared_made_for_kids, defaults.self_declared_made_for_kids),
    youtube_allow_publish_without_approval: toBoolean(config.allow_publish_without_approval, defaults.allow_publish_without_approval),
    youtube_title_suffix: String(config.title_suffix || defaults.title_suffix),
    youtube_description_footer: String(config.description_footer || defaults.description_footer),
  }
};

function buildFailure(message) {
  return {
    json: {
      ...$json,
      publish_upload_status: 'failed',
      publish_error: message,
      published_at: new Date().toISOString(),
    }
  };
}

function buildSuccess(extra) {
  return {
    json: {
      ...$json,
      publish_upload_status: 'uploaded',
      publish_error: null,
      published_at: new Date().toISOString(),
      approval_bypassed: $json.approval_mode === 'required' ? Boolean($json.youtube_allow_publish_without_approval) : false,
      ...extra,
    }
  };
}

function stringifyBody(value) {
  if (typeof value === 'string') return value;
  if (Buffer.isBuffer(value)) return value.toString('utf8');
  if (value && typeof value === 'object') return JSON.stringify(value).slice(0, 4000);
  return '';
}

const configError = String($json.youtube_config_error || '').trim();
if (configError) {
  return buildFailure(configError);
}

if (!$json.youtube_client_id || !$json.youtube_client_secret || !$json.youtube_refresh_token) {
  return buildFailure('Konfigurasi YouTube belum lengkap di /files/config/youtube_oauth.json.');
}

if ($json.approval_mode === 'required' && !$json.youtube_allow_publish_without_approval) {
  return buildFailure('approval_mode masih required dan bypass publish dimatikan di config YouTube.');
}

let title = String($json.title || '').trim();
const titleSuffix = String($json.youtube_title_suffix || '').trim();
if (titleSuffix) {
  title = [title, titleSuffix].filter(Boolean).join(' ').trim();
}
if (!title) {
  title = ('Shorts ' + String($json.job_id || '')).trim();
}
title = title.slice(0, 100);

let description = String($json.description || '').trim();
const footer = String($json.youtube_description_footer || '').trim();
if (footer) {
  description = [description, footer].filter(Boolean).join('\n\n');
}
description = description.slice(0, 5000);

const hashtags = Array.isArray($json.hashtags)
  ? $json.hashtags.map((tag) => String(tag || '').trim()).filter(Boolean)
  : [];
const tags = hashtags.map((tag) => tag.replace(/^#/, '')).filter(Boolean).slice(0, 15);
const desiredVisibility = String($json.youtube_privacy_status || 'private');
const uploadVisibility = desiredVisibility === 'private' ? 'private' : 'private';
const existingYoutubeResult = $json.existing_youtube_result || {};
const existingVideoId = String(existingYoutubeResult.video_id || $json.youtube_video_id || '').trim();

async function getAccessToken() {
  const tokenResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://oauth2.googleapis.com/token',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: [
      'client_id=' + encodeURIComponent(String($json.youtube_client_id)),
      'client_secret=' + encodeURIComponent(String($json.youtube_client_secret)),
      'refresh_token=' + encodeURIComponent(String($json.youtube_refresh_token)),
      'grant_type=refresh_token',
    ].join('&'),
    timeout: 120000,
  });
  return tokenResponse && tokenResponse.access_token ? String(tokenResponse.access_token) : '';
}

async function getVideoState(accessToken, videoId) {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://www.googleapis.com/youtube/v3/videos',
    qs: {
      part: 'status,processingDetails,snippet',
      id: videoId,
    },
    headers: {
      Authorization: 'Bearer ' + accessToken,
    },
    timeout: 120000,
    ignoreHttpStatusErrors: true,
    returnFullResponse: true,
  });

  const statusCode = response?.statusCode || response?.status || 0;
  if (statusCode >= 400) {
    throw new Error('Gagal cek status video YouTube :: status=' + String(statusCode) + ' :: ' + stringifyBody(response?.body));
  }

  const body = response && Object.prototype.hasOwnProperty.call(response, 'body') ? response.body : response;
  const parsed = typeof body === 'object' && body !== null && !Buffer.isBuffer(body)
    ? body
    : JSON.parse(stringifyBody(body) || '{}');
  const item = Array.isArray(parsed.items) ? parsed.items[0] : null;
  if (!item) {
    throw new Error('Video YouTube dengan id ' + videoId + ' tidak ditemukan saat cek processing status.');
  }
  return item;
}

async function updateVisibility(accessToken, videoId, videoState) {
  const currentStatus = videoState && videoState.status ? videoState.status : {};
  const currentPrivacy = String(currentStatus.privacyStatus || 'private');
  if (currentPrivacy === desiredVisibility) {
    return { privacyStatus: currentPrivacy, raw: videoState };
  }

  const response = await this.helpers.httpRequest({
    method: 'PUT',
    url: 'https://www.googleapis.com/youtube/v3/videos',
    qs: {
      part: 'status',
    },
    headers: {
      Authorization: 'Bearer ' + accessToken,
      'Content-Type': 'application/json; charset=UTF-8',
    },
    body: {
      id: videoId,
      status: {
        privacyStatus: desiredVisibility,
        selfDeclaredMadeForKids: Boolean($json.youtube_self_declared_made_for_kids),
      },
    },
    timeout: 120000,
    ignoreHttpStatusErrors: true,
    returnFullResponse: true,
  });

  const statusCode = response?.statusCode || response?.status || 0;
  if (statusCode >= 400) {
    throw new Error('Gagal ubah visibility YouTube :: status=' + String(statusCode) + ' :: ' + stringifyBody(response?.body));
  }

  const body = response && Object.prototype.hasOwnProperty.call(response, 'body') ? response.body : response;
  const parsed = typeof body === 'object' && body !== null && !Buffer.isBuffer(body)
    ? body
    : JSON.parse(stringifyBody(body) || '{}');
  return {
    privacyStatus: String(parsed?.status?.privacyStatus || desiredVisibility),
    raw: parsed,
  };
}

async function findReconciledVideo(accessToken) {
  if (!accessToken) return null;
  try {
    const searchResponse = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://www.googleapis.com/youtube/v3/search',
      qs: {
        part: 'snippet',
        forMine: 'true',
        type: 'video',
        maxResults: '10',
        order: 'date',
      },
      headers: {
        Authorization: 'Bearer ' + accessToken,
      },
      timeout: 120000,
    });

    const items = Array.isArray(searchResponse && searchResponse.items) ? searchResponse.items : [];
    const now = Date.now();
    const match = items.find((item) => {
      const videoId = item && item.id ? item.id.videoId : null;
      const snippet = item && item.snippet ? item.snippet : {};
      const publishedAt = Date.parse(snippet.publishedAt || snippet.publishTime || '');
      return Boolean(videoId)
        && String(snippet.title || '').trim() === title
        && String(snippet.description || '').trim() === description
        && Number.isFinite(publishedAt)
        && Math.abs(now - publishedAt) <= 30 * 60 * 1000;
    });

    if (!match || !match.id || !match.id.videoId) {
      return null;
    }

    return {
      youtube_video_id: String(match.id.videoId),
      youtube_watch_url: 'https://www.youtube.com/watch?v=' + String(match.id.videoId),
      youtube_studio_url: 'https://studio.youtube.com/video/' + String(match.id.videoId) + '/edit',
      youtube_uploaded_title: title,
      youtube_uploaded_description: description,
      youtube_uploaded_hashtags: hashtags,
      youtube_uploaded_tags: tags,
      youtube_privacy_status_effective: uploadVisibility,
      youtube_target_visibility: desiredVisibility,
      youtube_processing_status: 'processing',
      youtube_visibility_pending: true,
      youtube_api_response: {
        reconciled: true,
        search_match: match,
      },
    };
  } catch (reconcileError) {
    return null;
  }
}

let accessToken = '';

try {
  accessToken = await getAccessToken.call(this);
  if (!accessToken) {
    return buildFailure('Google OAuth tidak mengembalikan access_token.');
  }

  if (existingVideoId) {
    const videoState = await getVideoState.call(this, accessToken, existingVideoId);
    const processingStatus = String(videoState?.processingDetails?.processingStatus || videoState?.status?.uploadStatus || 'unknown');
    const currentPrivacy = String(videoState?.status?.privacyStatus || 'private');

    if (processingStatus !== 'succeeded') {
      return buildSuccess({
        youtube_video_id: existingVideoId,
        youtube_watch_url: 'https://www.youtube.com/watch?v=' + existingVideoId,
        youtube_studio_url: 'https://studio.youtube.com/video/' + existingVideoId + '/edit',
        youtube_uploaded_title: String(videoState?.snippet?.title || title),
        youtube_uploaded_description: String(videoState?.snippet?.description || description),
        youtube_uploaded_hashtags: hashtags,
        youtube_uploaded_tags: tags,
        youtube_privacy_status_effective: currentPrivacy,
        youtube_target_visibility: desiredVisibility,
        youtube_processing_status: processingStatus,
        youtube_visibility_pending: true,
        youtube_api_response: videoState,
      });
    }

    const visibilityUpdate = await updateVisibility.call(this, accessToken, existingVideoId, videoState);
    return buildSuccess({
      youtube_video_id: existingVideoId,
      youtube_watch_url: 'https://www.youtube.com/watch?v=' + existingVideoId,
      youtube_studio_url: 'https://studio.youtube.com/video/' + existingVideoId + '/edit',
      youtube_uploaded_title: String(videoState?.snippet?.title || title),
      youtube_uploaded_description: String(videoState?.snippet?.description || description),
      youtube_uploaded_hashtags: hashtags,
      youtube_uploaded_tags: tags,
      youtube_privacy_status_effective: visibilityUpdate.privacyStatus,
      youtube_target_visibility: desiredVisibility,
      youtube_processing_status: 'succeeded',
      youtube_visibility_pending: false,
      youtube_api_response: visibilityUpdate.raw,
    });
  }

  const binaryFieldName = $binary ? Object.keys($binary)[0] : null;
  if (!binaryFieldName) {
    return buildFailure('File clip utama tidak terbaca sebagai binary data.');
  }

  const clipBuffer = await this.helpers.getBinaryDataBuffer(0, binaryFieldName);
  const mimeType = String(($binary[binaryFieldName] && $binary[binaryFieldName].mimeType) || 'video/mp4');

  const metadata = {
    snippet: {
      title,
      description,
      categoryId: String($json.youtube_category_id || '22'),
    },
    status: {
      privacyStatus: uploadVisibility,
      selfDeclaredMadeForKids: Boolean($json.youtube_self_declared_made_for_kids),
    },
  };

  if (tags.length > 0) {
    metadata.snippet.tags = tags;
  }

  const initResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://www.googleapis.com/upload/youtube/v3/videos',
    qs: {
      uploadType: 'resumable',
      part: 'snippet,status',
      notifySubscribers: $json.youtube_notify_subscribers ? 'true' : 'false',
    },
    headers: {
      Authorization: 'Bearer ' + accessToken,
      'Content-Type': 'application/json; charset=UTF-8',
      'X-Upload-Content-Length': String(clipBuffer.length),
      'X-Upload-Content-Type': mimeType,
    },
    body: metadata,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });

  const initStatus = initResponse?.statusCode || initResponse?.status || 0;
  if (initStatus >= 400) {
    return buildFailure('Init upload YouTube gagal :: status=' + String(initStatus) + ' :: ' + stringifyBody(initResponse?.body));
  }

  const location = initResponse && initResponse.headers
    ? String(initResponse.headers.location || initResponse.headers.Location || '')
    : '';

  if (!location) {
    return buildFailure('Google tidak mengembalikan upload location untuk resumable upload.');
  }

  const uploadResponseRaw = await this.helpers.httpRequest({
    method: 'PUT',
    url: location,
    headers: {
      'Content-Type': mimeType,
    },
    body: clipBuffer,
    timeout: 300000,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });

  const uploadStatus = uploadResponseRaw?.statusCode || uploadResponseRaw?.status || 0;
  const uploadBody = uploadResponseRaw && Object.prototype.hasOwnProperty.call(uploadResponseRaw, 'body')
    ? uploadResponseRaw.body
    : uploadResponseRaw;
  const uploadBodyText = stringifyBody(uploadBody);

  if (uploadStatus >= 400) {
    const reconciled = await findReconciledVideo.call(this, accessToken);
    if (reconciled) {
      return buildSuccess(reconciled);
    }
    return buildFailure('Upload chunk YouTube gagal :: status=' + String(uploadStatus) + ' :: ' + uploadBodyText);
  }

  const uploadResponse = typeof uploadBody === 'object' && uploadBody !== null && !Buffer.isBuffer(uploadBody)
    ? uploadBody
    : JSON.parse(uploadBodyText || '{}');

  const videoId = uploadResponse && uploadResponse.id ? String(uploadResponse.id) : '';
  if (!videoId) {
    const reconciled = await findReconciledVideo.call(this, accessToken);
    if (reconciled) {
      return buildSuccess(reconciled);
    }
    return buildFailure('Upload YouTube selesai tapi video id tidak ditemukan di respons API. Respons: ' + uploadBodyText.slice(0, 1000));
  }

  const videoState = await getVideoState.call(this, accessToken, videoId);
  const processingStatus = String(videoState?.processingDetails?.processingStatus || videoState?.status?.uploadStatus || 'unknown');
  const currentPrivacy = String(videoState?.status?.privacyStatus || uploadVisibility);

  if (processingStatus !== 'succeeded') {
    return buildSuccess({
      youtube_video_id: videoId,
      youtube_watch_url: 'https://www.youtube.com/watch?v=' + videoId,
      youtube_studio_url: 'https://studio.youtube.com/video/' + videoId + '/edit',
      youtube_uploaded_title: title,
      youtube_uploaded_description: description,
      youtube_uploaded_hashtags: hashtags,
      youtube_uploaded_tags: tags,
      youtube_privacy_status_effective: currentPrivacy,
      youtube_target_visibility: desiredVisibility,
      youtube_processing_status: processingStatus,
      youtube_visibility_pending: true,
      youtube_api_response: videoState,
    });
  }

  const visibilityUpdate = await updateVisibility.call(this, accessToken, videoId, videoState);
  return buildSuccess({
    youtube_video_id: videoId,
    youtube_watch_url: 'https://www.youtube.com/watch?v=' + videoId,
    youtube_studio_url: 'https://studio.youtube.com/video/' + videoId + '/edit',
    youtube_uploaded_title: title,
    youtube_uploaded_description: description,
    youtube_uploaded_hashtags: hashtags,
    youtube_uploaded_tags: tags,
    youtube_privacy_status_effective: visibilityUpdate.privacyStatus,
    youtube_target_visibility: desiredVisibility,
    youtube_processing_status: 'succeeded',
    youtube_visibility_pending: false,
    youtube_api_response: visibilityUpdate.raw,
  });
} catch (error) {
  const reconciled = await findReconciledVideo.call(this, accessToken);
  if (reconciled) {
    return buildSuccess(reconciled);
  }

  const responseBody = error?.response?.body ?? error?.response?.data ?? error?.context ?? error?.cause ?? null;
  const responseText = stringifyBody(responseBody);
  const statusCode = error?.statusCode || error?.response?.statusCode || error?.response?.status || null;
  const parts = [];
  if (error?.message) parts.push(String(error.message));
  if (statusCode) parts.push('status=' + String(statusCode));
  if (responseText) parts.push(responseText);
  return buildFailure(parts.join(' :: ') || 'Gagal upload ke YouTube Data API.');
}

const isPending = Boolean($json.youtube_visibility_pending);
const result = {
  job_id: $json.job_id || null,
  stage: 'WF-03_PUBLISH_YOUTUBE_SHORTS',
  status: isPending ? 'YOUTUBE_PROCESSING_PENDING' : 'YOUTUBE_UPLOADED',
  published_at: $json.published_at || new Date().toISOString(),
  manifest_path: String($json.manifest_path || '').replace(/^\/files\//, 'shared/'),
  caption_result_path: String($json.caption_result_path || '').replace(/^\/files\//, 'shared/'),
  youtube_publish_result_path: String($json.youtube_publish_result_path || '').replace(/^\/files\//, 'shared/'),
  clip_path: String($json.clip_path || '').replace(/^\/files\//, 'shared/'),
  source_video_url: $json.source_video_url || null,
  source_video_id: $json.source_video_id || null,
  platform: 'youtube_shorts',
  approval_mode: $json.approval_mode || 'required',
  approval_bypassed: Boolean($json.approval_bypassed),
  privacy_status: $json.youtube_privacy_status_effective || 'private',
  target_visibility: $json.youtube_target_visibility || $json.youtube_privacy_status || 'private',
  processing_status: $json.youtube_processing_status || null,
  video_id: $json.youtube_video_id || null,
  youtube_watch_url: $json.youtube_watch_url || null,
  youtube_studio_url: $json.youtube_studio_url || null,
  title: $json.youtube_uploaded_title || $json.title || null,
  description: $json.youtube_uploaded_description || $json.description || null,
  hashtags: $json.youtube_uploaded_hashtags || $json.hashtags || [],
  next_stage: null,
};
const content = JSON.stringify(result, null, 2) + '\n';
return {
  json: {
    ...$json,
    youtube_publish_result_payload: result,
  },
  binary: {
    data: {
      data: Buffer.from(content, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: 'youtube_publish_result.json',
    }
  }
};

const result = {
  job_id: $json.job_id || null,
  stage: 'WF-03_PUBLISH_YOUTUBE_SHORTS',
  status: 'YOUTUBE_UPLOAD_FAILED',
  published_at: $json.published_at || new Date().toISOString(),
  manifest_path: String($json.manifest_path || '').replace(/^\/files\//, 'shared/'),
  caption_result_path: String($json.caption_result_path || '').replace(/^\/files\//, 'shared/'),
  youtube_publish_result_path: String($json.youtube_publish_result_path || '').replace(/^\/files\//, 'shared/'),
  clip_path: String($json.clip_path || '').replace(/^\/files\//, 'shared/'),
  source_video_url: $json.source_video_url || null,
  source_video_id: $json.source_video_id || null,
  platform: 'youtube_shorts',
  approval_mode: $json.approval_mode || 'required',
  approval_bypassed: false,
  privacy_status: $json.youtube_privacy_status || 'private',
  error_message: $json.publish_error || 'Upload YouTube gagal tanpa detail.',
  next_stage: null,
};
const content = JSON.stringify(result, null, 2) + '\n';
return {
  json: {
    ...$json,
    youtube_publish_result_payload: result,
  },
  binary: {
    data: {
      data: Buffer.from(content, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: 'youtube_publish_result.json',
    }
  }
};

function normalizeRepoPath(value) {
  if (!value) return null;
  return String(value).replace(/^\.\//, '').replace(/\\/g, '/');
}

function toContainerPath(value) {
  if (!value) return null;
  const normalized = normalizeRepoPath(value);
  if (normalized.startsWith('/files/')) return normalized;
  if (normalized.startsWith('shared/')) return '/files/' + normalized.slice('shared/'.length);
  if (normalized.startsWith('/')) return normalized;
  return '/files/' + normalized;
}

const binaryFieldName = $binary ? Object.keys($binary)[0] : null;
let existingYoutubeResult = null;
let existingYoutubeStatus = null;

if (binaryFieldName) {
  try {
    const rawBuffer = await this.helpers.getBinaryDataBuffer(0, binaryFieldName);
    const raw = rawBuffer.toString('utf8');
    existingYoutubeResult = JSON.parse(raw);
    existingYoutubeStatus = existingYoutubeResult && existingYoutubeResult.status ? String(existingYoutubeResult.status) : null;
  } catch (error) {
    existingYoutubeStatus = null;
  }
}

let manifestPath = toContainerPath($json.manifest_path);
const captionResultPath = toContainerPath($json.caption_result_path);
const youtubePublishResultPath = toContainerPath($json.youtube_publish_result_path);

if (!manifestPath && captionResultPath) {
  manifestPath = captionResultPath.replace(/caption_result\.json$/, 'manifest.json');
}
if (!manifestPath && youtubePublishResultPath) {
  manifestPath = youtubePublishResultPath.replace(/youtube_publish_result\.json$/, 'manifest.json');
}

return {
  json: {
    ...$json,
    manifest_path: manifestPath,
    caption_result_path: captionResultPath,
    youtube_publish_result_path: youtubePublishResultPath,
    existing_youtube_result: existingYoutubeResult,
    existing_youtube_status: existingYoutubeStatus,
  }
};

const binaryFieldName = $binary ? Object.keys($binary)[0] : null;
return {
  json: {
    ...$json,
    manifest_binary_available: Boolean(binaryFieldName),
    manifest_read_error: binaryFieldName ? null : ('Manifest file tidak terbaca dari path: ' + String($json.manifest_path || 'null')),
  },
  binary: $binary,
};

return {
  json: {
    ...$json,
    publish_upload_status: 'failed',
    publish_error: $json.manifest_read_error || 'Manifest file tidak terbaca.',
    published_at: new Date().toISOString(),
  }
};
